#define UART_RX_BUF_SIZE 256

static uint8_t uart_rx_buf[UART_RX_BUF_SIZE];
static volatile uint32_t uart_rx_head = 0;
static volatile uint32_t uart_rx_tail = 0;

void USART1_IRQHandler(void) {
    if (USART1->SR & USART_SR_RXNE) {
        uart_rx_buf[uart_rx_head] = USART1->DR;
        uart_rx_head = (uart_rx_head + 1) % UART_RX_BUF_SIZE;
    }
}

uint8_t uart_read(void) {
    while (uart_rx_head == uart_rx_tail);
    uint8_t data = uart_rx_buf[uart_rx_tail];
    uart_rx_tail = (uart_rx_tail + 1) % UART_RX_BUF_SIZE;
    return data;
}

void uart_dma_send(const uint8_t *data, uint32_t len) {
    DMA1_Channel4->CMAR = (uint32_t)data;
    DMA1_Channel4->CPAR = (uint32_t)&USART1->DR;
    DMA1_Channel4->CNDTR = len;
    DMA1_Channel4->CCR = DMA_CCR_MINC | DMA_CCR_DIR | DMA_CCR_TCIE;

    USART1->CR3 |= USART_CR3_DMAT;
    DMA1_Channel4->CCR |= DMA_CCR_EN;
}

void DMA1_Channel4_IRQHandler(void) {
    DMA1->IFCR = DMA_IFCR_CTCIF4;
    USART1->CR3 &= ~USART_CR3_DMAT;
}

