int uart_send_bytes(uart_dev_t *dev, const uint8_t *data, uint32_t len, uint32_t timeout_ms) {
    if (dev->tx_busy) {
        if (xSemaphoreTake(dev->tx_sem, pdMS_TO_TICKS(timeout_ms)) != pdTRUE)
            return -1;
    }
    dev->tx_busy = true;
    dev->tx_dma_buf = data;
    dev->tx_dma_len = len;

    DMA1_Channel4->CMAR = (uint32_t)data;
    DMA1_Channel4->CPAR = (uint32_t)&dev->uart->DR;
    DMA1_Channel4->CNDTR = len;
    DMA1_Channel4->CCR = DMA_CCR_MINC | DMA_CCR_DIR | DMA_CCR_TCIE;
    dev->uart->CR3 |= USART_CR3_DMAT;
    DMA1_Channel4->CCR |= DMA_CCR_EN;
    return 0;
}

